import React, { useEffect, useState, useContext, useRef, useCallback } from 'react';
import { AuthContext } from '../contexts/AuthContext';
import { useNavigate } from 'react-router-dom';
import { io } from 'socket.io-client';

const API_URL = 'http://localhost:3001';

export default function Lobby() {
  const { token, user, refreshUser, updateWallet } = useContext(AuthContext);
  const navigate = useNavigate();
  const socketRef = useRef(null);

  const [contestTypes, setContestTypes] = useState([]);
  const [myHistory, setMyHistory] = useState([]);
  const [activeTab, setActiveTab] = useState('contests');
  const [message, setMessage] = useState('');
  const [msgType, setMsgType] = useState('');

  // Waiting state (when player has joined a contest and waiting for opponent)
  const [waitingContestId, setWaitingContestId] = useState(null);
  const [waitingContestType, setWaitingContestType] = useState(null);
  const [waitTime, setWaitTime] = useState(0);

  // Opponent found state
  const [opponentFound, setOpponentFound] = useState(false);
  const [opponent, setOpponent] = useState(null);
  const [countdown, setCountdown] = useState(3);

  // Completed matches
  const [expandedMatch, setExpandedMatch] = useState(null);

  // Social & Bonus
  const [lobbyChatMessages, setLobbyChatMessages] = useState([]);
  const lobbyChatRef = useRef(null);
  const [bonusClaimed, setBonusClaimed] = useState(false);

  // ── Fetch Data ──
  const fetchContests = useCallback(async () => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/api/contests`, { headers: { Authorization: `Bearer ${token}` } });
      if (res.ok) setContestTypes(await res.json());
    } catch (e) {}
  }, [token]);

  const fetchHistory = useCallback(async () => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/api/contests/my-history`, { headers: { Authorization: `Bearer ${token}` } });
      if (res.ok) setMyHistory(await res.json());
    } catch (e) {}
  }, [token]);

  useEffect(() => {
    fetchContests(); fetchHistory();
    const iv = setInterval(fetchContests, 5000);
    return () => clearInterval(iv);
  }, [fetchContests, fetchHistory]);

  // ── Socket ──
  useEffect(() => {
    if (!user?.id) return;
    if (!socketRef.current) socketRef.current = io(API_URL);
    const socket = socketRef.current;

    socket.emit('identify', { userId: user.id });

    // When opponent is found (both players in contest)
    socket.on('opponentFound', (data) => {
      setOpponentFound(true);
      setOpponent(data.opponent);
      setCountdown(data.countdown || 3);

      // Count down
      let c = data.countdown || 3;
      const iv = setInterval(() => {
        c--;
        setCountdown(c);
        if (c <= 0) clearInterval(iv);
      }, 1000);
    });

    // Match started → navigate to game room
    socket.on('matchStarted', (data) => {
      setWaitingContestId(null);
      setWaitingContestType(null);
      setOpponentFound(false);
      setWaitTime(0);
      navigate(`/room/${data.contestId}`);
    });

    // Player left contest
    socket.on('contestLeft', (data) => {
      setWaitingContestId(null);
      setWaitingContestType(null);
      setOpponentFound(false);
      setWaitTime(0);
      if (data.refunded) {
        showMsg('Entry fee refunded ✅');
        refreshUser();
      }
    });

    // Contest error
    socket.on('contestError', (data) => {
      setWaitingContestId(null);
      setWaitingContestType(null);
      showMsg(data.message || 'Failed to join contest', 'error');
    });

    // Waiting for opponent confirmation
    socket.on('waitingForOpponent', (data) => {
      setWaitingContestId(data.contestId);
      setWaitingContestType(data.contestType);
      setWaitTime(0);
    });

    // Contest updated (someone joined/left) — refresh lobby
    socket.on('contestUpdated', () => {
      fetchContests();
    });

    socket.on('lobbyChat', (msgData) => {
      setLobbyChatMessages(prev => [...prev, msgData].slice(-50));
      setTimeout(() => {
        if (lobbyChatRef.current) lobbyChatRef.current.scrollTop = lobbyChatRef.current.scrollHeight;
      }, 50);
    });

    socket.on('walletUpdate', (data) => {
      if (data.wallet !== undefined) updateWallet(data.wallet);
    });

    return () => {
      socket.removeAllListeners();
    };
  }, [user?.id]);

  // Wait timer
  useEffect(() => {
    if (!waitingContestId || opponentFound) return;
    const iv = setInterval(() => setWaitTime(t => t + 1), 1000);
    return () => clearInterval(iv);
  }, [waitingContestId, opponentFound]);

  const showMsg = (msg, type = 'success') => {
    setMessage(msg); setMsgType(type);
    setTimeout(() => setMessage(''), 5000);
  };

  const claimDailyBonus = async () => {
    try {
      const res = await fetch(`${API_URL}/api/bonus/claim`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await res.json();
      if (res.ok) {
        setBonusClaimed(true);
        showMsg(`🎁 Daily Bonus: ₹${data.amount} added! Streak: Day ${data.streak}/7`);
        refreshUser();
      } else {
        showMsg(data.message, 'error');
      }
    } catch (e) {}
  };

  // ── Join Contest (direct — no matchmaking) ──
  const handleJoinContest = (contestType, contestId) => {
    if (!user) return;
    if (waitingContestId) {
      showMsg('Already waiting for a match. Cancel first.', 'error');
      return;
    }

    // Wallet check (frontend guard)
    if (contestType.entry > 0 && (user.wallet || 0) < contestType.entry) {
      showMsg(`Insufficient balance! Need ₹${contestType.entry}, have ₹${user.wallet}`, 'error');
      return;
    }

    // Send join via socket — server handles wallet deduction + match start
    socketRef.current?.emit('joinContest', { contestId, userId: user.id });
  };

  // ── Cancel waiting ──
  const handleCancelWait = () => {
    if (waitingContestId) {
      socketRef.current?.emit('leaveContest', { contestId: waitingContestId, userId: user.id });
    }
    setWaitingContestId(null);
    setWaitingContestType(null);
    setOpponentFound(false);
    setWaitTime(0);
  };

  const tabs = [
    { key: 'contests', label: 'Contests', icon: '⚔️', count: contestTypes.length },
    { key: 'history', label: 'History', icon: '📋', count: myHistory.length },
  ];

  const formatDate = (date) => {
    if (!date) return '';
    const d = new Date(date);
    const now = new Date();
    const diff = now - d;
    if (diff < 86400000 && d.getDate() === now.getDate()) return 'Today';
    if (diff < 172800000) return 'Yesterday';
    return d.toLocaleDateString('en-IN', { day: 'numeric', month: 'short' });
  };

  const formatTime = (seconds) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  // Group contest types by category
  const grouped = {
    'Free Match': contestTypes.filter(ct => ct.entry === 0),
    'Quick Match': contestTypes.filter(ct => ct.entry > 0 && ct.name.startsWith('Quick')),
    'Battle': contestTypes.filter(ct => ct.entry > 0 && ct.name.startsWith('Battle')),
    'Premium': contestTypes.filter(ct => ct.entry > 0 && !ct.name.startsWith('Quick') && !ct.name.startsWith('Battle')),
  };

  return (
    <div className="min-h-screen bg-hero">
      <div className="max-w-7xl mx-auto px-4 py-6 flex flex-col lg:flex-row gap-6">
        <div className="flex-1">
          {/* Hero */}
          <div className="mb-6 flex flex-wrap justify-between items-end gap-4 animate-fade-in">
            <div>
              <h1 className="text-3xl sm:text-4xl font-black tracking-tight text-white mb-1">
                Chess <span className="text-gradient-green">Arena</span>
              </h1>
              <p className="text-slate-400 text-sm">Play, compete, and win real prizes</p>
              <p className="text-[10px] text-slate-600 mt-1">🎯 This is a game of skill. Must be 18+ to play.</p>
            </div>
            {!bonusClaimed && (
              <button 
                onClick={claimDailyBonus}
                className="bg-gradient-to-r from-amber-500 to-orange-500 hover:from-amber-400 hover:to-orange-400 text-white font-black px-5 py-2.5 rounded-xl shadow-lg shadow-orange-500/20 transform hover:-translate-y-0.5 transition-all text-sm flex items-center gap-2"
              >
                <span className="text-lg">🎁</span> Claim Daily Bonus
              </button>
            )}
          </div>

          {message && (
            <div className={`mb-4 p-3 rounded-xl border animate-slide-down text-sm font-medium ${
              msgType === 'error' ? 'bg-red-500/10 border-red-500/20 text-red-400' : 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400'
            }`}>{message}</div>
          )}

          {/* Waiting Overlay */}
          {waitingContestId && (
            <div className="mb-6 animate-slide-down">
              <div className="card border-chess-green/20 bg-chess-green/5">
                {!opponentFound ? (
                  <div className="flex items-center justify-between gap-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-full bg-chess-green/15 flex items-center justify-center">
                        <div className="w-5 h-5 border-2 border-chess-green border-t-transparent rounded-full animate-spin" />
                      </div>
                      <div>
                        <p className="text-white font-bold text-sm">Waiting for opponent...</p>
                        <p className="text-slate-400 text-xs">{waitingContestType?.name} • {formatTime(waitTime)}</p>
                      </div>
                    </div>
                    <button onClick={handleCancelWait} className="btn-secondary btn-sm text-xs">Cancel</button>
                  </div>
                ) : (
                  <div className="text-center py-4">
                    <div className="text-4xl mb-2">⚔️</div>
                    <p className="text-white font-bold">Opponent Found!</p>
                    <p className="text-chess-green font-bold text-lg">{opponent?.username} (ELO {opponent?.elo || 1200})</p>
                    <p className="text-slate-400 text-sm mt-1">Starting in <span className="text-chess-green font-black text-xl">{countdown}</span></p>
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Tabs */}
          <div className="flex gap-1 bg-navy-800/50 backdrop-blur-sm rounded-xl p-1 mb-6">
            {tabs.map(tab => (
              <button key={tab.key} onClick={() => { setActiveTab(tab.key); if (tab.key === 'history') fetchHistory(); }}
                className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-medium transition-all ${
                  activeTab === tab.key ? 'bg-chess-green/15 text-chess-green border border-chess-green/10' : 'text-slate-400 hover:text-white hover:bg-white/5'
                }`}>
                <span>{tab.icon}</span> {tab.label}
                {tab.count > 0 && <span className={`px-1.5 py-0.5 rounded-full text-[10px] font-bold ${
                  activeTab === tab.key ? 'bg-chess-green/20 text-chess-green' : 'bg-navy-700 text-slate-500'
                }`}>{tab.count}</span>}
              </button>
            ))}
          </div>

          {/* ═══ CONTESTS TAB ═══ */}
          {activeTab === 'contests' && (
            <div className="space-y-8 animate-fade-in">
              {Object.entries(grouped).map(([category, types]) => {
                if (types.length === 0) return null;
                return (
                  <div key={category}>
                    <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-3 flex items-center gap-2">
                      <span className={category === 'Free Match' ? 'text-sky-400' : category === 'Quick Match' ? 'text-chess-green' : category === 'Battle' ? 'text-gold-400' : 'text-purple-400'}>
                        {category === 'Free Match' ? '✌️' : category === 'Quick Match' ? '⚡' : category === 'Battle' ? '⚔️' : '👑'}
                      </span>
                      {category}
                    </h2>
                  <div className="grid sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                    {types.map((ct, idx) => (
                      <ContestCard
                        key={ct._id}
                        ct={ct}
                        user={user}
                        onJoin={handleJoinContest}
                        delay={idx * 60}
                        isWaiting={waitingContestId !== null}
                      />
                    ))}
                  </div>
                </div>
              );
            })}

            {contestTypes.length === 0 && (
              <div className="card text-center py-16">
                <div className="w-12 h-12 mx-auto rounded-full bg-navy-700/50 flex items-center justify-center mb-3">
                  <div className="w-6 h-6 border-2 border-chess-green border-t-transparent rounded-full animate-spin" />
                </div>
                <p className="text-slate-400">Loading contests...</p>
              </div>
            )}
          </div>
        )}

        {/* ═══ HISTORY TAB ═══ */}
        {activeTab === 'history' && (
          <div className="animate-fade-in">
            {myHistory.length === 0 ? (
              <div className="card text-center py-16">
                <span className="text-5xl mb-4 block">🎮</span>
                <p className="text-slate-400 font-medium">No completed matches yet</p>
                <p className="text-slate-500 text-sm mt-1">Join a contest to start playing!</p>
              </div>
            ) : (
              <div className="space-y-2">
                {myHistory.map(contest => {
                  const isWinner = contest.winner?._id?.toString() === user?.id || contest.winner?.toString() === user?.id;
                  const isDraw = !contest.winner && ['draw', 'stalemate'].includes(contest.reason);
                  const ct = contest.contestType;
                  const isExpanded = expandedMatch === contest._id;
                  const opponentName = contest.whitePlayer?._id?.toString() === user?.id
                    ? contest.blackPlayer?.username
                    : contest.whitePlayer?.username;

                  return (
                    <div key={contest._id}>
                      <button onClick={() => setExpandedMatch(isExpanded ? null : contest._id)}
                        className="w-full flex items-center gap-3 p-3 rounded-xl bg-navy-800/50 border border-navy-700/20 hover:border-navy-600/30 transition-all text-left">
                        <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm flex-shrink-0 ${
                          isWinner ? 'bg-chess-green/15 text-chess-green' : isDraw ? 'bg-slate-500/15 text-slate-400' : 'bg-red-500/15 text-red-400'
                        }`}>
                          {isWinner ? '🏆' : isDraw ? '🤝' : '💔'}
                        </div>

                        <div className="flex-1 min-w-0">
                          <p className="text-sm font-medium text-white truncate">vs {opponentName || 'Unknown'}</p>
                          <p className="text-[10px] text-slate-500">{ct?.name} • {contest.reason}</p>
                        </div>

                        <div className="text-right flex-shrink-0">
                          <p className={`text-sm font-bold ${isWinner ? 'text-chess-green' : isDraw ? 'text-slate-400' : 'text-red-400'}`}>
                            {isWinner ? `+₹${ct?.payout || 0}` : isDraw ? `+₹${ct?.entry || 0}` : `-₹${ct?.entry || 0}`}
                          </p>
                          <p className="text-[10px] text-slate-600">{formatDate(contest.endedAt)}</p>
                        </div>

                        <span className="text-slate-500 text-xs ml-2">{isExpanded ? '▲' : '▼'}</span>
                      </button>

                      {isExpanded && (
                        <div className="ml-11 mt-1 p-3 rounded-xl bg-navy-800/30 border border-navy-700/10 animate-slide-down">
                          <div className="grid grid-cols-3 gap-3 text-xs mb-3">
                            <div><span className="text-slate-500">Entry</span><p className="text-white font-bold">₹{ct?.entry}</p></div>
                            <div><span className="text-slate-500">Prize</span><p className="text-gold-400 font-bold">₹{ct?.payout}</p></div>
                            <div><span className="text-slate-500">Moves</span><p className="text-white font-bold">{contest.moves?.length || 0}</p></div>
                          </div>
                          <button onClick={() => navigate(`/room/${contest._id}`)} className="btn-sm btn-secondary w-full">📊 View Details</button>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  </div>
  );
}

// ── Contest Card Component ──
function ContestCard({ ct, user, onJoin, delay, isWaiting }) {
  const hasBalance = ct.entry === 0 || (user?.wallet || 0) >= ct.entry;
  const waitingCount = ct.waitingCount || 0;
  const isHot = waitingCount > 0;

  // Pick the first open contest with a player already in it, or any empty one
  const targetContestId = ct.waitingPlayers?.[0]?.contestId || ct.emptyContests?.[0];

  // Check if current user is already waiting in one of these contests
  const userIsWaiting = ct.waitingPlayers?.some(wp => 
    wp.player?._id?.toString() === user?.id || wp.player?.toString() === user?.id
  );

  return (
    <div className={`contest-card animate-slide-up ${isHot ? 'ring-1 ring-chess-green/20' : ''}`}
      style={{ animationDelay: `${delay}ms` }}>

      {/* Hot indicator */}
      {isHot && (
        <div className="absolute top-3 right-3">
          <span className="relative flex h-2.5 w-2.5">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-chess-green opacity-50"></span>
            <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-chess-green"></span>
          </span>
        </div>
      )}

      {/* Name */}
      <h3 className="text-base font-bold text-white mb-3">{ct.name}</h3>

      {/* Prize card */}
      <div className="p-3 rounded-xl bg-navy-900/60 border border-navy-700/20 mb-3">
        <div className="flex items-center justify-between">
          <div>
            <p className="text-[10px] text-slate-500 uppercase tracking-wider">Entry</p>
            <p className="text-xl font-black text-white">{ct.entry === 0 ? 'FREE' : `₹${ct.entry}`}</p>
          </div>
          <div className="text-xl text-slate-600">→</div>
          <div className="text-right">
            <p className="text-[10px] text-slate-500 uppercase tracking-wider">Win</p>
            <p className="text-xl font-black text-chess-green">{ct.payout === 0 ? 'ELO' : `₹${ct.payout}`}</p>
          </div>
        </div>
      </div>

      {/* Player count & profit */}
      <div className="flex items-center justify-between mb-3">
        {ct.entry > 0 ? (
          <span className="badge bg-chess-green/10 text-chess-green border border-chess-green/20 text-[10px]">
            +{Math.round(((ct.payout - ct.entry) / ct.entry) * 100)}% return
          </span>
        ) : (
          <span className="badge bg-sky-400/10 text-sky-400 border border-sky-400/20 text-[10px]">
            Free Practice
          </span>
        )}
        <span className="text-[10px] text-slate-500">
          {waitingCount > 0 ? (
            <span className="text-chess-green font-bold">{waitingCount} waiting</span>
          ) : (
            `${ct.openCount || 0} open`
          )}
        </span>
      </div>

      {/* Waiting player info */}
      {isHot && ct.waitingPlayers?.[0]?.player && !userIsWaiting && (
        <div className="mb-3 p-2 rounded-lg bg-chess-green/5 border border-chess-green/10 flex items-center gap-2">
          <div className="w-6 h-6 rounded-full bg-chess-green/20 flex items-center justify-center text-xs font-bold text-chess-green flex-shrink-0">
            {ct.waitingPlayers[0].player.username?.charAt(0)?.toUpperCase()}
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-xs text-white truncate">{ct.waitingPlayers[0].player.username}</p>
            <p className="text-[10px] text-slate-500">ELO {ct.waitingPlayers[0].player.elo || 1200}</p>
          </div>
          <span className="text-[10px] text-chess-green font-bold animate-pulse">Waiting...</span>
        </div>
      )}

      {/* Join button */}
      {userIsWaiting ? (
        <button className="w-full py-3 rounded-xl text-sm font-bold bg-amber-500/10 border border-amber-500/20 text-amber-400 cursor-default">
          ⏳ You're waiting...
        </button>
      ) : hasBalance ? (
        <button
          onClick={() => onJoin(ct, targetContestId)}
          disabled={!targetContestId || isWaiting}
          className={`w-full py-3 rounded-xl text-sm font-black transition-all active:scale-[0.98] ${
            isWaiting
              ? 'bg-slate-500/10 border border-slate-500/20 text-slate-400 cursor-not-allowed'
              : isHot
                ? 'bg-gradient-to-r from-chess-green to-emerald-600 text-white shadow-lg shadow-chess-green/20 hover:shadow-chess-green/40'
                : 'bg-gradient-to-r from-chess-green/90 to-emerald-600/90 text-white hover:from-chess-green hover:to-emerald-600'
          }`}
        >
          {isHot ? '⚡ Join Now' : '🎮 Play'} — {ct.entry === 0 ? 'Free' : `₹${ct.entry}`}
        </button>
      ) : (
        <button className="w-full py-3 rounded-xl text-sm font-bold bg-red-500/10 border border-red-500/20 text-red-400 cursor-not-allowed">
          💳 Add Money — Need ₹{ct.entry}
        </button>
      )}
    </div>
  );
}
